1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty set for empty grid", () => {
6	    expect(nextGeneration(new Set())).toEqual(new Set());
7	  });
8	  it("should kill single living cell (underpopulation)", () => {
9	    const liveCell = new Set(["0,0"]);
10	    expect(nextGeneration(liveCell)).toEqual(new Set());
11	  });
12	  it("should kill two adjacent cells (both underpopulation)", () => {
13	    const twoCells = new Set(["0,0", "1,0"]);
14	    expect(nextGeneration(twoCells)).toEqual(new Set());
15	  });
16	  it("should preserve living cell with exactly 2 neighbors", () => {
17	    // Create a configuration where one cell has exactly 2 neighbors
18	    // Cells at (0,0), (0,1), (0,2) form a vertical line
19	    // - (0,0) has 1 neighbor (0,1)
20	    // - (0,1) has 2 neighbors (0,0) and (0,2)
21	    // - (0,2) has 1 neighbor (0,1)
22	    // Next generation: (0,1) should survive with 2 neighbors
23	    const cells = new Set(["0,0", "0,1", "0,2"]);
24	    const result = nextGeneration(cells);
25	    expect(result.has("0,1")).toBe(true);
26	  });
27	  it("should preserve living cell with exactly 3 neighbors", () => {
28	    // Create a configuration where one cell has exactly 3 neighbors
29	    // A 2x2 block has each cell with 3 neighbors:
30	    // (0,0) has neighbors (0,1), (1,0), (1,1) = 3 neighbors ✓
31	    // (0,1) has neighbors (0,0), (1,0), (1,1) = 3 neighbors ✓
32	    // (1,0) has neighbors (0,0), (0,1), (1,1) = 3 neighbors ✓
33	    // (1,1) has neighbors (0,0), (0,1), (1,0) = 3 neighbors ✓
34	    // All cells should survive
35	    const cells = new Set(["0,0", "0,1", "1,0", "1,1"]);
36	    const result = nextGeneration(cells);
37	    expect(result.has("0,0")).toBe(true);
38	  });
39	  it("should kill cell with 4 neighbors (overpopulation)", () => {
40	    // Create a configuration where one cell has exactly 4 neighbors
41	    // Pattern:
42	    //   (0,1)
43	    // (1,0) X (1,2)
44	    //   (2,1)
45	    //   + one more neighbor (0,0)
46	    // This gives X at (1,1) exactly 4 neighbors: (0,1), (1,0), (1,2), (2,1)
47	    // Plus (0,0) for 5 total? Let me create a 3x3 with center having 4 neighbors:
48	    // (0,0) (0,1) empty
49	    // (1,0)   X   (1,2)
50	    // empty (2,1) empty
51	    // X at (1,1) has 4 neighbors: (0,0), (0,1), (1,0), (1,2), (2,1) = 5 neighbors
52	    // Let me use: (0,0), (0,1), (1,0), (1,2) - this gives (1,1) exactly 4 neighbors
53	    const cells = new Set(["0,0", "0,1", "1,0", "1,2"]);
54	    const result = nextGeneration(cells);
55	    expect(result.has("1,1")).toBe(false);
56	  });
57	  it("should create new cell from dead cell with exactly 3 neighbors", () => {
58	    // Dead cell at (1,1) with exactly 3 living neighbors should be born
59	    // Pattern: three cells forming an L-shape around a dead cell
60	    // (0,1) (1,1) dead
61	    // (1,0) - center (1,1) is dead
62	    // (0,0) is empty
63	    // Living cells: (0,1), (1,0), (0,0) - these 3 are neighbors of dead cell (1,1)
64	    const cells = new Set(["0,0", "0,1", "1,0"]);
65	    const result = nextGeneration(cells);
66	    expect(result.has("1,1")).toBe(true);
67	  });
68	  it("should handle multiple births in one generation", () => {
69	    // Configuration where multiple dead cells will be born
70	    // Pattern: three cells in an L-shape create conditions for births
71	    // Living cells: (0,0), (0,1), (1,0)
72	    // Dead cell (1,1) has 3 neighbors: (0,0), (0,1), (1,0) -> will be born
73	    // Dead cell (0,2) has 2 neighbors: (0,1), (0,0) -> will not be born
74	    // Dead cell (2,0) has 2 neighbors: (0,0), (1,0) -> will not be born
75	    // Dead cell (2,1) has 2 neighbors: (0,1), (1,0) -> will not be born
76	    // Dead cell (-1,0) has 1 neighbor: (0,0) -> will not be born
77	    // So we need a more complex pattern for multiple births
78	    // Use pattern that creates 2+ cells with exactly 3 neighbors
79	    const cells = new Set(["0,1", "1,0", "1,1", "1,2", "2,1"]);
80	    const result = nextGeneration(cells);
81	    // After checking, multiple dead cells should have exactly 3 neighbors
82	    // Dead cell (0,0) has neighbors (0,1), (1,0), (1,1) = 3 -> born
83	    // Dead cell (2,0) has neighbors (1,0), (1,1), (2,1) = 3 -> born
84	    // Dead cell (2,2) has neighbors (1,1), (1,2), (2,1) = 3 -> born
85	    // Dead cell (0,2) has neighbors (0,1), (1,1), (1,2) = 3 -> born
86	    expect(result.has("0,0")).toBe(true);
87	    expect(result.has("2,0")).toBe(true);
88	    expect(result.has("2,2")).toBe(true);
89	    expect(result.has("0,2")).toBe(true);
90	  });
91	  it("should handle multiple deaths in one generation", () => {
92	    // Configuration where multiple living cells will die
93	    // Start with a pattern where several cells have insufficient neighbors
94	    // Pattern: 5 isolated cells or cells with < 2 neighbors
95	    // Living cells: (0,0), (2,0), (4,0) - all isolated (0 neighbors each)
96	    const cells = new Set(["0,0", "2,0", "4,0"]);
97	    const result = nextGeneration(cells);
98	    // All three cells should die due to underpopulation
99	    expect(result.has("0,0")).toBe(false);
100	    expect(result.has("2,0")).toBe(false);
101	    expect(result.has("4,0")).toBe(false);
102	  });
103	  it.todo("should handle mixed births and deaths");
104	  it.todo("should handle negative coordinates");
105	});
